module f3_mult(A, B, C); 
    input [1:0] A;
    input [1:0] B; 
    output [1:0] C;
    wire inv_a0, a1, b0, b1;
    assign {a1, inv_a0} = A;
    assign {b1, b0} = B;
    assign C[0] = (~a1 & inv_a0 & ~b1 & b0) | (a1 & ~inv_a0 & b1 & ~b0);
    assign C[1] = (~a1 & inv_a0 & b1 & ~b0) | (a1 & ~inv_a0 & ~b1 & b0);
endmodule
